function escHtml(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function fmtDateTime(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt.getTime())) return '—';
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  }) + ' at ' + dt.toLocaleTimeString('en-GB', {
    hour: '2-digit',
    minute: '2-digit'
  });
}
function render(model) {
  var body = document.getElementById('jobsheet_body');
  if (!body) return;
  var c = model.collection || {};
  if (!c.collection_vehicle && !c.driver_signature) {
    body.innerHTML = '<div class="empty">No job sheet submitted yet</div>';
    return;
  }
  body.innerHTML = '<div class="meta-grid">' + '<div class="meta-item"><div class="meta-label">Vehicle</div><div class="meta-value">' + escHtml(c.collection_vehicle || '—') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Driver</div><div class="meta-value">' + escHtml(c.driver || '—') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Customer On-Site</div><div class="meta-value">' + escHtml(c.client_name_onsite || '—') + '</div></div>' + '</div>' + '<div class="meta-item" style="grid-column: 1 / -1;"><div class="meta-label">Signed On</div><div class="meta-value">' + fmtDateTime(c.client_signature_timestamp) + '</div></div>' + '<div class="sig-row">' + '<div class="sig-block"><label>Driver Signature</label>' + (c.driver_signature ? '<img src="' + c.driver_signature + '"/>' : '<div class="empty">Not signed</div>') + '</div>' + '<div class="sig-block"><label>Customer Signature</label>' + (c.client_signature ? '<img src="' + c.client_signature + '"/>' : '<div class="empty">Not signed</div>') + '</div>' + '</div>';
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function () {
    render(appsmith.model);
  });
  appsmith.onModelChange(function (model) {
    render(model);
  });
}
initWhenReady();

